const base64 = $json.base64 || '';
const mimetype = ($json.mimetype || 'audio/ogg; codecs=opus').split(';')[0];
const ext = mimetype.includes('mp4') ? 'mp4' : 'ogg';

if (!base64) {
  // Evolution API não retornou áudio — Whisper vai falhar (continueOnFail)
  // e Code Set Transcript vai lidar com $json.text vazio
  return [{ json: { mimetype, _no_audio: true }, binary: {} }];
}

return [{
  json: { mimetype },
  binary: {
    audio: {
      data: base64,
      mimeType: mimetype,
      fileName: `audio.${ext}`,
    }
  }
}];

const transcript = ($json.text || '').trim();
const original = $('Set Phone').item.json;

// Se Whisper falhou, injeta marcador para a Raquel pedir repetição naturalmente
const message = transcript || '[AUDIO_NAO_TRANSCRITO]';

return [{
  json: {
    ...original,
    message
  }
}];

const visionResult = ($json.choices?.[0]?.message?.content || '').trim();
const original = $('Set Phone').item.json;
const caption = original.message || '';

// Injeta a descrição como contexto invisível para a Raquel
// O prefixo [IMAGEM_REF:] é interpretado pelo system prompt
const message = visionResult
  ? `[IMAGEM_REF: ${visionResult}]${caption ? '\n' + caption : ''}`
  : caption;

return [{
  json: {
    ...original,
    message,
    vision_description: visionResult
  }
}];

const data = $('Webhook').item.json.body.data;
const key = data.key;
const audioMsg = data.message.audioMessage;

// Constrói body plaintext para evitar problema de proxy n8n em expressões HTTP
return [{
  json: {
    _evo_audio_request: {
      message: {
        key: {
          remoteJid: String(key.remoteJid || ''),
          fromMe:    Boolean(key.fromMe),
          id:        String(key.id || '')
        },
        message: {
          audioMessage: JSON.parse(JSON.stringify(audioMsg))
        }
      },
      convertToMp4: false
    }
  }
}];

const data = $('Webhook').item.json.body.data;
const key = data.key;
const imgMsg = data.message.imageMessage;

return [{
  json: {
    _evo_image_request: {
      message: {
        key: {
          remoteJid: String(key.remoteJid || ''),
          fromMe:    Boolean(key.fromMe),
          id:        String(key.id || '')
        },
        message: {
          imageMessage: JSON.parse(JSON.stringify(imgMsg))
        }
      },
      convertToMp4: false
    }
  }
}];
